function UserCard({userId}: {userId: string}) {
  const [user, setUser] = useState<User | null>(null);
  const [fullName, setFullName] = useState("");

  if (!userId) return null;  // BUG 1: early return before hooks below
  useEffect(() => {
    fetch(`/api/users/${userId}`).then(r => r.json()).then(setUser);
  }, []);  // BUG 2: missing userId in deps
  useEffect(() => {
    if (user) setFullName(`${user.first} ${user.last}`);  // BUG 3: sync-via-effect
  }, [user]);

  return <div>{fullName}</div>;
}

function UserCard({userId}: {userId: string}) {
  const [user, setUser] = useState<User | null>(null);

  useEffect(() => {
    if (!userId) return;
    const controller = new AbortController();
    fetch(`/api/users/${userId}`, {signal: controller.signal})
      .then(r => r.json())
      .then(setUser)
      .catch(err => { if (err.name !== 'AbortError') throw err; });
    return () => controller.abort();  // FIX 1: cleanup, FIX 2: deps complete
  }, [userId]);

  if (!userId || !user) return null;        // FIX 3: early return AFTER hooks
  const fullName = `${user.first} ${user.last}`;  // FIX 4: derive in render

  return <div>{fullName}</div>;
}
